import React, { useState, useEffect } from "react";
import api from "../api/api";
import Pagination from "../components/Pagination";
import { FaEdit, FaTrash, FaPlus, FaSearch, FaImage } from "react-icons/fa";

const API_URL = "http://localhost:5000";

export default function Productos() {
  const [productos, setProductos] = useState([]);
  const [categorias, setCategorias] = useState([]);
  const [productoActual, setProductoActual] = useState({
    _id: null,
    nombre: "",
    descripcion: "",
    precio: "",
    stock: "",
    categoria_id: "", // Aquí guardaremos el ID, no el nombre
    imagen: null,
  });

  const [showModal, setShowModal] = useState(false);
  const [modoEdicion, setModoEdicion] = useState(false);
  const [busqueda, setBusqueda] = useState("");
  const [imagenModal, setImagenModal] = useState(null);

  // Paginación
  const [paginaActual, setPaginaActual] = useState(1);
  const productosPorPagina = 6;

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    try {
      const [resProd, resCat] = await Promise.all([
        api.get("/productos"),
        api.get("/categorias"),
      ]);
      setProductos(resProd.data);
      setCategorias(resCat.data); // Cargamos las categorías tal cual vienen de Mongo (_id, nombre)
    } catch (error) {
      console.error("❌ Error al cargar datos:", error);
    }
  };

  const handleChange = (e) => {
    setProductoActual({ ...productoActual, [e.target.name]: e.target.value });
  };

  const handleFileChange = (e) => {
    setProductoActual({ ...productoActual, imagen: e.target.files[0] });
  };

  const abrirModalAgregar = () => {
    setProductoActual({
      _id: null,
      nombre: "",
      descripcion: "",
      precio: "",
      stock: "",
      categoria_id: "",
      imagen: null,
    });
    setModoEdicion(false);
    setShowModal(true);
  };
  const abrirModalEditar = (p) => {
    setProductoActual({
      _id: p._id,
      nombre: p.nombre,
      descripcion: p.descripcion,
      precio: p.precio,
      stock: p.stock,
      // ⬇️ ESTA ES LA CLAVE: Extraer el ID del objeto poblado
      categoria_id: p.categoria_id?._id || p.categoria_id,
      imagen: null,
    });
    setModoEdicion(true);
    setShowModal(true);
  };

  const guardarProducto = async (e) => {
    e.preventDefault();

    // DEBUG: Para que veas en consola qué se está enviando antes del error
    console.log("Enviando ID de categoría:", productoActual.categoria_id);

    const formData = new FormData();
    formData.append("nombre", productoActual.nombre);
    formData.append("descripcion", productoActual.descripcion);
    formData.append("precio", productoActual.precio);
    formData.append("stock", productoActual.stock);
    formData.append("categoria_id", productoActual.categoria_id); // Este debe ser el ID de 24 caracteres

    if (productoActual.imagen) {
      formData.append("imagen", productoActual.imagen);
    }

    try {
      if (modoEdicion) {
        await api.put(`/productos/${productoActual._id}`, formData, {
          headers: { "Content-Type": "multipart/form-data" },
        });
      } else {
        await api.post("/productos", formData, {
          headers: { "Content-Type": "multipart/form-data" },
        });
      }

      setShowModal(false);
      cargarDatos();
      alert("✨ Producto guardado exitosamente");
    } catch (error) {
      console.error(error);
      alert(
        "❌ Error: " +
          (error.response?.data?.detalle || "Revisa la consola del servidor"),
      );
    }
  };

  const eliminarProducto = async (id) => {
    if (window.confirm("¿Deseas eliminar este producto?")) {
      try {
        await api.delete(`/productos/${id}`);
        cargarDatos();
      } catch (error) {
        console.error("❌ Error al eliminar:", error);
      }
    }
  };

  const productosFiltrados = productos.filter((p) =>
    (p.nombre?.toLowerCase() || "").includes(busqueda.toLowerCase()),
  );

  const inicio = (paginaActual - 1) * productosPorPagina;
  const productosPaginados = productosFiltrados.slice(
    inicio,
    inicio + productosPorPagina,
  );

  return (
    <div className="container mt-4">
      <div className="card border-0 shadow-sm p-4 mb-4 bg-white rounded-4">
        <div className="row align-items-center">
          <div className="col-md-6">
            <h3 className="fw-bold m-0 text-dark">📦 Gestión de Productos</h3>
          </div>
          <div className="col-md-6 text-md-end mt-3 mt-md-0">
            <button
              className="btn btn-primary px-4 fw-bold shadow-sm"
              onClick={abrirModalAgregar}
            >
              <FaPlus className="me-2" /> Nuevo Producto
            </button>
          </div>
        </div>
      </div>

      <div className="card border-0 shadow-sm mb-4 rounded-4">
        <div className="card-body">
          <div className="input-group">
            <span className="input-group-text bg-light border-0">
              <FaSearch className="text-muted" />
            </span>
            <input
              type="text"
              placeholder="Buscar por nombre..."
              className="form-control border-0 bg-light"
              value={busqueda}
              onChange={(e) => {
                setBusqueda(e.target.value);
                setPaginaActual(1);
              }}
            />
          </div>
        </div>
      </div>

      <div className="table-responsive shadow-sm rounded-4 overflow-hidden">
        <table className="table table-hover align-middle mb-0 bg-white">
          <thead className="table-dark">
            <tr className="text-center">
              <th>Imagen</th>
              <th>Producto</th>
              <th>Categoría</th>
              <th>Precio</th>
              <th>Stock</th>
              <th>Acciones</th>
            </tr>
          </thead>
          <tbody>
            {productosPaginados.map((p) => (
              <tr key={p._id} className="text-center">
                <td>
                  {p.imagen ? (
                    <img
                      src={`${API_URL}/uploads/${p.imagen}`}
                      alt={p.nombre}
                      className="rounded-3 shadow-sm"
                      style={{
                        width: "45px",
                        height: "45px",
                        objectFit: "cover",
                        cursor: "zoom-in",
                      }}
                      onClick={() => setImagenModal(p.imagen)}
                    />
                  ) : (
                    <FaImage className="text-muted fs-4" />
                  )}
                </td>
                <td className="fw-bold">{p.nombre}</td>
                <td>
                  <span className="badge bg-light text-dark border">
                    {p.categoria_id?.nombre || "Sin Categoría"}
                  </span>
                </td>
                <td className="text-primary fw-bold">
                  ${parseFloat(p.precio).toFixed(2)}
                </td>
                <td>
                  <span
                    className={`badge ${p.stock < 5 ? "bg-danger" : "bg-success"}`}
                  >
                    {p.stock} unidades
                  </span>
                </td>
                <td>
                  <button
                    className="btn btn-sm btn-outline-warning border-0 me-1"
                    onClick={() => abrirModalEditar(p)}
                  >
                    <FaEdit />
                  </button>
                  <button
                    className="btn btn-sm btn-outline-danger border-0"
                    onClick={() => eliminarProducto(p._id)}
                  >
                    <FaTrash />
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <Pagination
        totalItems={productosFiltrados.length}
        itemsPerPage={productosPorPagina}
        currentPage={paginaActual}
        onPageChange={(page) => setPaginaActual(page)}
      />

      {showModal && (
        <div
          className="modal show d-block"
          style={{
            backgroundColor: "rgba(0,0,0,0.5)",
            backdropFilter: "blur(4px)",
          }}
        >
          <div className="modal-dialog modal-dialog-centered modal-lg">
            <div className="modal-content border-0 rounded-4 shadow-lg">
              <div className="modal-header border-0 bg-primary text-white p-4">
                <h5 className="modal-title fw-bold">
                  {modoEdicion ? "Actualizar Producto" : "Crear Nuevo Producto"}
                </h5>
                <button
                  className="btn-close btn-close-white"
                  onClick={() => setShowModal(false)}
                ></button>
              </div>
              <form onSubmit={guardarProducto}>
                <div className="modal-body p-4">
                  <div className="row g-3">
                    <div className="col-md-8">
                      <label className="form-label fw-bold small text-muted">
                        Nombre del Producto
                      </label>
                      <input
                        type="text"
                        name="nombre"
                        value={productoActual.nombre}
                        onChange={handleChange}
                        className="form-control bg-light border-0"
                        required
                      />
                    </div>
                    <div className="col-md-4">
                      <label className="form-label fw-bold small text-muted">
                        Categoría
                      </label>
                      <select
                        name="categoria_id"
                        value={productoActual.categoria_id}
                        onChange={handleChange}
                        className="form-select"
                        required
                      >
                        <option value="">Seleccione...</option>
                        {categorias.map((c) => (
                          <option key={c._id} value={c._id}>
                            {" "}
                            {/* 👈 Aquí DEBE ir c._id */}
                            {c.nombre}
                          </option>
                        ))}
                      </select>
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small text-muted">
                        Precio ($)
                      </label>
                      <input
                        type="number"
                        step="0.01"
                        name="precio"
                        value={productoActual.precio}
                        onChange={handleChange}
                        className="form-control bg-light border-0"
                        required
                      />
                    </div>
                    <div className="col-md-6">
                      <label className="form-label fw-bold small text-muted">
                        Stock Disponible
                      </label>
                      <input
                        type="number"
                        name="stock"
                        value={productoActual.stock}
                        onChange={handleChange}
                        className="form-control bg-light border-0"
                        required
                      />
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold small text-muted">
                        Descripción
                      </label>
                      <textarea
                        name="descripcion"
                        value={productoActual.descripcion}
                        onChange={handleChange}
                        className="form-control bg-light border-0"
                        rows="3"
                      ></textarea>
                    </div>
                    <div className="col-12">
                      <label className="form-label fw-bold small text-muted">
                        Foto del Producto
                      </label>
                      <input
                        type="file"
                        className="form-control bg-light border-0"
                        onChange={handleFileChange}
                      />
                    </div>
                  </div>
                </div>
                <div className="modal-footer border-0 p-4">
                  <button
                    type="button"
                    className="btn btn-light px-4 fw-bold"
                    onClick={() => setShowModal(false)}
                  >
                    Cancelar
                  </button>
                  <button
                    type="submit"
                    className="btn btn-primary px-4 fw-bold shadow-sm"
                  >
                    Guardar
                  </button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {imagenModal && (
        <div
          className="modal show d-flex align-items-center justify-content-center"
          style={{
            backgroundColor: "rgba(0,0,0,0.85)",
            position: "fixed",
            top: 0,
            left: 0,
            width: "100%",
            height: "100%",
            zIndex: 3000,
          }}
          onClick={() => setImagenModal(null)}
        >
          <img
            src={`${API_URL}/uploads/${imagenModal}`}
            alt="Zoom"
            className="img-fluid rounded-4 shadow-lg"
            style={{ maxHeight: "80vh" }}
          />
        </div>
      )}
    </div>
  );
}
